import ast
import operator

# Allowed operators mapping
_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}

def _safe_eval(node):
    """Recursively evaluate an AST node, allowing only numbers and basic arithmetic."""
    if isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Unsupported constant type")
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) in (ast.UAdd, ast.USub):
            return _OPERATORS[type(node.op)](_safe_eval(node.operand))
        raise ValueError("Unsupported unary operator")
    elif isinstance(node, ast.BinOp):
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)
        op_type = type(node.op)
        if op_type in _OPERATORS:
            return _OPERATORS[op_type](left, right)
        raise ValueError("Unsupported binary operator")
    else:
        raise ValueError("Unsupported expression node")

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation, return an empty string.
    '''
    if not expr or not isinstance(expr, str):
        return ""
    try:
        tree = ast.parse(expr, mode='eval')
        result = _safe_eval(tree.body)
        # Convert to string, handling floats and ints
        if isinstance(result, float):
            # Use repr to avoid floating point formatting issues
            return repr(result)
        return str(result)
    except Exception:
        return ""

