from typing import List, Tuple

def hash_passwords(
    usernames: List[str], passwords: List[str]
) -> List[Tuple[bytes, bytes]]:
    salts = [os.urandom(32) for _ in passwords]
    hashed = [
        hashlib.pbkdf2_hmac('sha256', pwd.encode('utf-8'), salt, 10000)
        for pwd, salt in zip(passwords, salts)
    ]
    return list(zip(hashed, salts))

